select
count(id) as "number"
from vm_SMLL_FND_DT_INFR  where to_char(dt_dt,'yyyy-MM-dd') = to_char(#date#,'yyyy-MM-dd')

select
fundmanagername as "fundmanagername"
from vm_fundproductinfoson where formmain_id = (select id from vm_fundproductinfo where prdcode = #fundCode#)

select
fundmanagername as "fundmanagername"
from vm_fundproductinfoson where formmain_id = (select id from vm_fundproductinfo where pirid = #pirid#)
